# Employee hierarchy module - defines base and derived classes

@abstract
class Employee:
    name: str
    salary: float

    def __init__(self, name: str, salary: float):
        self.name = name
        self.salary = salary

    @virtual
    def get_role(self) -> str:
        return "Employee"

    @virtual
    def calculate_bonus(self) -> float:
        return self.salary * 0.05

class Manager(Employee):
    team_size: int

    def __init__(self, name: str, salary: float, team_size: int):
        super().__init__(name, salary)
        self.team_size = team_size

    @override
    def get_role(self) -> str:
        return "Manager"

    @override
    def calculate_bonus(self) -> float:
        return self.salary * 0.10 + float(self.team_size) * 500.0

class Developer(Employee):
    language: str

    def __init__(self, name: str, salary: float, language: str):
        super().__init__(name, salary)
        self.language = language

    @override
    def get_role(self) -> str:
        return "Developer"

    @override
    def calculate_bonus(self) -> float:
        base: float = self.salary * 0.08
        if self.language == "Python":
            base = base + 1000.0
        return base

def get_employee_summary(emp: Employee) -> str:
    return f"{emp.name} ({emp.get_role()})"

