# Reporting module - imports from models to generate reports

from models import Employee, Manager, Developer, get_employee_summary

def generate_report(employees: list[Employee]) -> None:
    total_salary: float = 0.0
    total_bonus: float = 0.0
    manager_count: int = 0

    for emp in employees:
        total_salary = total_salary + emp.salary
        total_bonus = total_bonus + emp.calculate_bonus()
        if isinstance(emp, Manager):
            manager_count = manager_count + 1

    print(f"Total Salary: {total_salary}")
    print(f"Total Bonus: {total_bonus}")
    print(f"Manager Count: {manager_count}")

def find_by_role(employees: list[Employee], role: str) -> list[Employee]:
    result: list[Employee] = []
    for emp in employees:
        if emp.get_role() == role:
            result.append(emp)
    return result
